document.addEventListener("DOMContentLoaded", () => {
    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

    const navLinks = Array.from(document.querySelectorAll("[data-nav-link]"));
    const sections = Array.from(document.querySelectorAll("[data-nav-section]"));

    const setActiveNav = (id) => {
        navLinks.forEach((link) => {
            link.classList.toggle("is-active", link.dataset.navLink === id);
        });
    };

    setActiveNav("home");

    if ("IntersectionObserver" in window && sections.length > 0) {
        const navObserver = new IntersectionObserver(
            (entries) => {
                const visibleEntry = entries
                    .filter((entry) => entry.isIntersecting)
                    .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];

                if (visibleEntry) {
                    setActiveNav(visibleEntry.target.dataset.navSection);
                }
            },
            {
                rootMargin: "-30% 0px -55% 0px",
                threshold: [0.15, 0.35, 0.6]
            }
        );

        sections.forEach((section) => {
            navObserver.observe(section);
        });
    }

    const heroSlides = Array.from(document.querySelectorAll("[data-hero-slide]"));
    let currentHeroSlide = 0;
    let heroSlideTimer = null;

    const setHeroSlide = (index) => {
        if (heroSlides.length === 0) {
            return;
        }

        const wrappedIndex = ((index % heroSlides.length) + heroSlides.length) % heroSlides.length;
        currentHeroSlide = wrappedIndex;

        heroSlides.forEach((slide, slideIndex) => {
            slide.classList.toggle("is-active", slideIndex === wrappedIndex);
        });
    };

    const startHeroRotation = () => {
        if (prefersReducedMotion || heroSlides.length < 2 || heroSlideTimer !== null) {
            return;
        }

        heroSlideTimer = window.setInterval(() => {
            setHeroSlide(currentHeroSlide + 1);
        }, 6800);
    };

    const stopHeroRotation = () => {
        if (heroSlideTimer === null) {
            return;
        }

        window.clearInterval(heroSlideTimer);
        heroSlideTimer = null;
    };

    if (heroSlides.length > 0) {
        setHeroSlide(0);
        startHeroRotation();
    }

    const videoShell = document.querySelector("[data-main-video-shell]");
    const videoPlayer = document.querySelector("[data-main-video-player]");
    const videoButton = document.querySelector("[data-main-video-button]");

    const loadMainVideo = () => {
        if (!videoShell || !videoPlayer || videoPlayer.querySelector("video")) {
            return;
        }

        const src = videoShell.dataset.videoSrc;
        const video = document.createElement("video");
        const source = document.createElement("source");

        video.className = "main-video";
        video.controls = true;
        video.playsInline = true;
        video.preload = "metadata";

        source.src = src;
        source.type = "video/mp4";

        video.appendChild(source);
        videoPlayer.appendChild(video);
        videoShell.classList.add("is-loaded");

        const playPromise = video.play();
        if (playPromise && typeof playPromise.catch === "function") {
            playPromise.catch(() => {});
        }
    };

    if (videoButton) {
        videoButton.addEventListener("click", loadMainVideo);
    }

    const galleryVideos = Array.from(document.querySelectorAll(".gallery-video"));
    const galleryTrack = document.querySelector("[data-gallery-track]");
    const galleryPages = Array.from(document.querySelectorAll("[data-gallery-page]"));
    const galleryDots = Array.from(document.querySelectorAll("[data-gallery-dot]"));
    const galleryPrevButton = document.querySelector("[data-gallery-prev]");
    const galleryNextButton = document.querySelector("[data-gallery-next]");
    let currentGalleryPage = 0;

    const ensureVideoSource = (video) => {
        if (!video || video.dataset.ready === "true") {
            return;
        }

        const source = video.querySelector("source[data-src]");
        if (!source) {
            return;
        }

        source.src = source.dataset.src;
        video.dataset.ready = "true";
        video.load();

        video.addEventListener(
            "loadeddata",
            () => {
                const mediaFrame = video.closest("[data-gallery-media]");
                if (mediaFrame) {
                    mediaFrame.classList.add("is-ready");
                }
            },
            { once: true }
        );
    };

    const pauseAllGalleryVideos = () => {
        galleryVideos.forEach((video) => {
            video.pause();
        });
    };

    const playWhenVisible = (video) => {
        ensureVideoSource(video);
        if (prefersReducedMotion) {
            return;
        }

        const playPromise = video.play();
        if (playPromise && typeof playPromise.catch === "function") {
            playPromise.catch(() => {});
        }
    };

    const setGalleryPage = (index) => {
        if (!galleryTrack || galleryPages.length === 0) {
            return;
        }

        const wrappedIndex = ((index % galleryPages.length) + galleryPages.length) % galleryPages.length;
        currentGalleryPage = wrappedIndex;
        galleryTrack.style.transform = `translateX(-${wrappedIndex * 100}%)`;

        galleryPages.forEach((page, pageIndex) => {
            page.setAttribute("aria-hidden", pageIndex === wrappedIndex ? "false" : "true");
        });

        galleryDots.forEach((dot, dotIndex) => {
            dot.classList.toggle("is-active", dotIndex === wrappedIndex);
        });

        pauseAllGalleryVideos();

        window.requestAnimationFrame(() => {
            const activePage = galleryPages[wrappedIndex];
            const trackRect = galleryTrack.getBoundingClientRect();

            if (!activePage || trackRect.bottom <= 0 || trackRect.top >= window.innerHeight) {
                return;
            }

            activePage.querySelectorAll(".gallery-video").forEach((video) => {
                playWhenVisible(video);
            });
        });
    };

    if (galleryDots.length > 0) {
        galleryDots.forEach((dot) => {
            dot.addEventListener("click", () => {
                setGalleryPage(Number(dot.dataset.galleryDot || 0));
            });
        });

        setGalleryPage(0);
    }

    if (galleryPrevButton) {
        galleryPrevButton.addEventListener("click", () => {
            setGalleryPage(currentGalleryPage - 1);
        });
    }

    if (galleryNextButton) {
        galleryNextButton.addEventListener("click", () => {
            setGalleryPage(currentGalleryPage + 1);
        });
    }

    if ("IntersectionObserver" in window) {
        const preloadObserver = new IntersectionObserver(
            (entries, observer) => {
                entries.forEach((entry) => {
                    if (!entry.isIntersecting) {
                        return;
                    }

                    ensureVideoSource(entry.target);
                    observer.unobserve(entry.target);
                });
            },
            {
                rootMargin: "420px 0px",
                threshold: 0.01
            }
        );

        const playbackObserver = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    const video = entry.target;
                    if (entry.isIntersecting) {
                        playWhenVisible(video);
                    } else {
                        video.pause();
                    }
                });
            },
            {
                threshold: 0.35
            }
        );

        galleryVideos.forEach((video) => {
            preloadObserver.observe(video);
            playbackObserver.observe(video);
        });
    } else {
        galleryVideos.forEach((video) => {
            ensureVideoSource(video);
            playWhenVisible(video);
        });
    }

    const copyButton = document.querySelector("[data-copy-citation]");
    const citationBlock = document.querySelector("#citation-bibtex");

    const copyCitation = async () => {
        if (!copyButton || !citationBlock) {
            return;
        }

        const text = citationBlock.textContent || "";

        try {
            if (navigator.clipboard && navigator.clipboard.writeText) {
                await navigator.clipboard.writeText(text);
            } else {
                const selection = window.getSelection();
                const range = document.createRange();
                range.selectNodeContents(citationBlock);
                selection.removeAllRanges();
                selection.addRange(range);
                document.execCommand("copy");
                selection.removeAllRanges();
            }

            const originalText = copyButton.textContent;
            copyButton.textContent = "Copied";
            copyButton.classList.add("is-copied");

            window.setTimeout(() => {
                copyButton.textContent = originalText;
                copyButton.classList.remove("is-copied");
            }, 1600);
        } catch (error) {
            copyButton.textContent = "Copy failed";
        }
    };

    if (copyButton) {
        copyButton.addEventListener("click", copyCitation);
    }

    document.addEventListener("visibilitychange", () => {
        if (document.hidden) {
            stopHeroRotation();
            pauseAllGalleryVideos();
            return;
        }

        startHeroRotation();
    });
});
